<template>
      <div class="menu">
        <div @click='toRouter("")' :class="index == 1 ? 'nav active' : 'nav'">
          <div class="nav_bg"></div>
          <h4>设备明细<br/>(GNSS)</h4>
          <div class="arrow"></div>
        </div>
        <div @click='toRouter("interaction")' :class="index == 2 ? 'nav active' : 'nav'">
          <div class="nav_bg"></div>
          <h4>风险筛选</h4>
          <div class="arrow"></div>
        </div>
        <div @click='toRouter("pie")' :class="index == 3 ? 'nav active' : 'nav'">
          <div class="nav_bg"></div>
          <h4>寿命预测</h4>
          <div class="arrow"></div>
        </div>
        <div @click='toRouter("map")' :class="index == 4 ? 'nav active' : 'nav'">
          <div class="nav_bg"></div>
          <h4>数据分析</h4>
          <div class="arrow"></div>
        </div>
      </div>
</template>

<script>
export default {
    name:'Nav',
    props:['index'],
    mounted() {

    },
    methods: {
        toRouter(router){
            this.$router.push({
                path:'/'+router
            })
        }
    },
}
</script>


