<template >
  <div class="main"  v-loading="loading">
    <div class="content ">
        <el-dialog
            class="indexdialog"
            :append-to-body = 'true'
            title="提示"
            :visible.sync="centerDialogVisible"
            width="30%"
            center>
            
            <el-card class="box-card">
                <div slot="header" class="clearfix">
                    <span>当前设备信息</span>
                    <el-button @click="toDetail(dataDetail['ID'])" style="float: right; padding: 3px 0" type="text">查看详细</el-button>
                </div>
                <div>
                <p>医院名称:{{dataDetail['医院']}}</p>
                <p>生产厂家:{{dataDetail['生产厂家']}}</p>
                <p>型号规格:{{dataDetail['型号规格']}}</p>
                <p>医院所在区县:{{dataDetail['医院所在区县']}}</p>
                <p>球管安装时间:{{dataDetail['球管安装时间']}}</p>
                <p>最后检定日期:{{dataDetail['数据检定日期']}}</p>

  
                </div>
            </el-card>


            <span slot="footer" class="dialog-footer">
                <el-button @click="centerDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="centerDialogVisible = false">确 定</el-button>
            </span>
        </el-dialog>


      <Nav index = '1'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京市计量检测科学研究院
              </h1>
        <div class="row height100">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">设备地址</h4>
              <div class="card_show map">
                <!-- <el-input  :fetch-suggestions="querySearch" class="mapinput" v-model="hos_name" placeholder="请输入医院名称"/> -->
                    <el-autocomplete
                      class="inline-input mapinput"
                      v-model="hos_name"
                      :fetch-suggestions="querySearch"
                      placeholder="请输入内容"
                      @select="handleSelect"
                    ></el-autocomplete>
                <div class="img_map" id ='allmap'>
            
                </div>
              </div>
            </div>
          </div>
        </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'

export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      hos_name:"",
      activeIndex:0,
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      timer:null,
      marker:[],
      data:[],
      map:null,
      dataDetail:{},
      centerDialogVisible:false,
      loading:true
    }
  },
  mounted() {

  },
  created(){
    this.getData()
  },
  methods: {
      handleSelect(val){
        console.log(val.obj)
        var point = new   BMap.Point(val.obj["设备经度"],val.obj['设备纬度']);
        this.map.centerAndZoom(point, 15);
      },
      search(val){
        alert(val)
      },
      getData(){
          this.$axios({
            methods:"get",
            url:"http://47.105.205.80:8880/all",
          }).then((res)=>{
            this.data = res.data;
            this.loading = false
            this.initMap();
          })
      },
      querySearch(queryString, cb) {
        // var restaurants = this.restaurants;
        // var results = queryString ? restaurants.filter(this.createFilter(queryString)) : restaurants;
        // 调用 callback 返回建议列表的数据

        var rs = [];
        for (let index = 0; index < this.data.length; index++) {
          if( this.data[index]['医院'].indexOf(queryString) !== -1){
            var o = {
              value:this.data[index]['医院'],
              id:this.data[index]['ID'],
              obj:this.data[index]
            }
            
            rs.push(o)
          }          
        }




        //  方法1：利用对象访问属性的方法，判断对象中是否存在key
        var result = [];
        var obj = {};
        for(var i =0; i<rs.length; i++){
            if(!obj[rs[i].value]){
              result.push(rs[i]);
              obj[rs[i].value] = true;
            }
        }
        console.log(result); 



        // var results =   [{ "value": "三全鲜食（北新泾店）", "address": "长宁区新渔路144号" },
        //              { "value": "Hot honey 首尔炸鸡（仙霞路）", "address": "上海市长宁区淞虹路661号" }]
        cb(result);
      },

      toDetail(id){
          this.$router.push({
              path:'pie',
              query:{
              id:id
            }
          })
      },
      initMap(){
            this.map = new BMap.Map("allmap" ,{
              enableMapClick:false
            });
            var point = new   BMap.Point(116.405419,39.914271);
            this.map.enableScrollWheelZoom();                            //启用滚轮放大缩小
            this.map.centerAndZoom(point, 5); 
            // this.map.setMapStyle({style:'midnight'});
              var markers = [];
              var pt = null;
              for (let i = 0; i < this.markers.length; i++) {
                pt = new BMap.Point(this.markers[i]['lon'], this.markers[i]['lat']);
                 var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(50,50) );
                var el = new BMap.Marker(pt , {
                  icon:myIcon
                });
               
                el.addEventListener('click' , (val)=>{
                    this.activeIndex = i
                    this.centerDialogVisible = true;
                    this.dataDetail = this.data[i];
                })
                markers.push(el);
              }
              console.log(this.markers)
              //最简单的用法，生成一个marker数组，然后调用markerClusterer类即可。
              var markerClusterer = new BMapLib.MarkerClusterer(this.map, {markers:markers});
      }
  },
  computed:{

    // 地图点
    markers(){
      let arr = [];
      for (let index = 0; index < this.data.length; index++) {
        var o = {
          id : this.data[index]["ID"],
          lon : this.data[index]['设备经度'],
          lat : this.data[index]['设备纬度'],
        }
        arr.push(o);
      }
      return arr
    },
    mapList(){
      var arr  = [
        {
          "id":1
        }
      ];
      for (let index = 0; index < this.myData.length; index++) {
          if( (arr[arr.length - 1]['ID'] !== this.myData[index]['ID'])){
            arr.push(this.myData[index])
          }


      }
      arr = arr.slice(1 , arr.length)
      return arr;
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



