<template>
  <div id="app" ref = 'app'>
    <router-view/>
  </div>
</template>

<script>

export default {
  name: 'App',
  data(){
    return {
      fullWidth : null, 
      fullHeight : null,
      loading :true
    }
  },
  mounted() {
    this.fullHeight =   `${document.documentElement.clientHeight}`  
    this.fullWidth =   `${document.documentElement.clientWidth}`    
    window.onresize = function temp() {
      this.fullHeight =   `${document.documentElement.clientHeight}`  
      this.fullWidth =   `${document.documentElement.clientWidth}` 
    };

    if(parseInt(this.fullHeight) > parseInt(this.fullWidth)){
      alert('请旋转手机,在横屏下运行此系统');
    } 

          // this.$axios({
          //   methods:"get",
          //   url:"http://47.105.205.80:8880/all",
          // }).then((res)=>{
          //   this.gData = res.data;
          //   this.loading = false
          // })

  },
  watch: {
    fullWidth:function(){
      this.renderDisplay()
    }
  },
  methods: {
    renderDisplay : function(){
      var scale = this.fullWidth / 1920 -0.08;
      this.$refs.app.style.transform = ' scale('+scale+')';
    }
  },
}
</script>

