<template>
  <div class="main"  v-loading="loading">
    <div class="content">
    
        <Nav index = '3'/>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京市计量检测科学研究院
              </h1>
        <div class="row height100">
            <div class="col width60 height100">
                <div class="col_inner height60">
                <div class="card active">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">筛选</h4>
                      <div class="card_show"> 
                        <div class="model_table">
                          <div class="col">
                            <div class="row">医院名称</div>
                            <div class="row" style='position:relative'>
                              <el-select @change='change($event)' v-model="vala" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagLista"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">厂家</div>
                            <div class="row">
                              <el-select v-model="valb" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListb"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">型号</div>
                            <div class="row">
                              <el-select v-model="valc" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListc"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">等级</div>
                            <div class="row">
                            <el-select v-model="vald" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListd"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">所在地</div>
                            <div class="row">
                            <el-select v-model="vale" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListe"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                          <div class="col">
                            <div class="row">球管安装时间</div>
                            <div class="row">
                            <el-select v-model="valf" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListf"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>

                          <div class="col">
                            <div class="row">选择ID</div>
                            <div class="row">
                              <el-input v-model="id"/>
                            </div>
                          </div>
          
                        </div>
                          <div class='pie_button'>
                            <el-button @click="resrt">重 &nbsp; &nbsp; &nbsp;   置</el-button>
                            <el-button @click="handleEnter">筛  &nbsp; &nbsp; &nbsp;   选</el-button>
                          </div>
                      </div>
                </div>
                </div>
                 <div class="col_inner height40 padding_top30">
                    <div class="card active ">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">详细信息</h4>
                <div class="model_table" style="height:100% ; overflow:scroll">

                  <div class="col">



                    <div class="row">名称</div>

        
                    <div class="row">信息</div>


                  </div>
    
                  <div class="col">
                    <div class="row">医院名称</div>

                    <div class="row">{{detailData['医院']}}</div>
                  </div>

                  <div class="col">
                    <div class="row">生产厂家</div>

                    <div class="row">{{detailData['生产厂家']}}</div>
                  </div>

                  <div class="col">
                    <div class="row">型号规格</div>

                    <div class="row">{{detailData['型号规格']}}</div>
                  </div>

                  <div class="col">
                    <div class="row">医院所在地</div>

                    <div class="row">{{detailData['医院所在区县']}}</div>
                  </div>
                  <div class="col">
                    <div class="row">风险等级</div>

                    <div class="row">{{detailData['风险等级']}}</div>
                  </div>
                  <div class="col">
                    <div class="row">球管安装时间</div>

                    <div class="row">{{detailData['球管安装时间']}}</div>
                  </div>
                  <div class="col">
                    <div class="row">最后检定日期</div>

                    <div class="row">{{detailData['数据检定日期']}}</div>
                  </div>
                </div>
                    </div>
                </div>
            </div>
            <div class="col width40 height100">
              <div style="height:40% ;padding-bottom:20px">
                <div class="card active" >
                      <b></b>
                      <b></b>
                      <b></b>
                      <b></b>
                      <div class="line a"></div>
                      <div class="line a"></div>
                      <div class="line a"></div>
                      <div class="line a"></div>
                      <h4 class="card_title">线性计算结果</h4>
                      <div class="card_show">
                          <div class="linechart height100" ref= 'mychartb'></div>
                        
                      </div>
                </div>
              </div>
   

                <div class="card active" style="height:40%">
                  <b></b>
                  <b></b>
                  <b></b>
                  <b></b>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <h4 class="card_title">重复性计算结果</h4>
                  <div class="card_show">
                      <div class="linechart height100" ref= 'mycharta'></div>
                    </div>
                </div>

                <div style="height:20% ; padding-top:30px">
                <div class="card active modal_width_warp" >
                  <b></b>
                  <b></b>
                  <b></b>
                  <b></b>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <div class="line a"></div>
                  <h4 class="card_title">剩余寿命</h4>
                  <div class="modal_width">
                    <div class="detail" :style="widthStyle">{{detailData['剩余寿命']}}</div>
                  </div>
                </div>
                </div>
              </div>
              </div>
          </div>
        </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'

export default {
  name: 'Interaction',
  components:{Nav},
  data () {
    return {
      loading : true,
      id:null,
      chart:null,
      tableData:[
        ['北京航星医院', 'DR 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城'],
        ['北京航星医院', 'AX 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城']
      ],
      data:[],
      vala:'',
      valb:'',
      valc:'',
      vald:'',
      vale:'',
      valf:'',
      itemData:{
            "医院名称": "",
            "厂家": "",
            "型号": "",
            "医院等级": "",
            "所在地": "",
            "球馆安装时间": "",
            "设备ID": ""
    },
    }
  },
  created(){
    this.getData()
  },
  mounted() {
      this.id = this.$route.query.id ? this.$route.query.id  : null ;
      this.initLine()
  },
  watch:{

  },
  methods: {
    resrt(){
        this.vala = ''
        this.valb = ''
        this.valc = ''
        this.vald = ''
        this.vale = ''
        this.valf = ''
    },
    handleEnter(){
      this.initLine();
    },
    getData(){
          this.$axios({
            methods:"get",
            url:"http://47.105.205.80:8880/all",
          }).then((res)=>{
            this.loading = false
            this.data = res.data;
            this.initLine();
            if(this.id !== null){
              console.log(this.detailData)
              
            
            
            
            
            
                      this.vala = this.detailData['医院']
                      this.valb = this.detailData['生产厂家']
                      this.valc = this.detailData['型号规格']
                      this.vald = this.detailData['风险等级']
                      this.vale = this.detailData['医院所在区县']
                      this.valf = this.detailData['球管安装时间']
            }
          })
      },
      initLine(){
          
            if(this.detailData.ID !== null){
              let arra = this.detailData["线性计算结果"].substring(1,  this.detailData["线性计算结果"].length-1)
         
      
              arra = arra.split(',')
 
              let arrb = this.detailData["重复性计算结果"].substring(1,  this.detailData["重复性计算结果"].length-1)

              arrb = arrb.split(',')
            




            
            let arraunit = []
            let arrbunit = []

            for (let index = 0; index < arra.length; index++) {
              arra[index] =  parseFloat(arra[index].substring(1, arra[index].length - 1)) 
              arraunit.push(index)              
            }


            for (let index = 0; index < arrb.length; index++) {
              arrb[index] =  parseFloat(arrb[index].substring(1, arrb[index].length - 1)) 
              arrbunit.push(index)              
            }

    


            // 基于准备好的dom，初始化echarts实例
            // 基于准备好的dom，初始化echarts实例
            var myCharta = echarts.init(this.$refs.mycharta);

            var myChartb = echarts.init(this.$refs.mychartb);



            var option = {
                xAxis: {
                    type: 'category',
                    data: arraunit,
                    axisLabel: {
                        textStyle: {
                            color: "#83ecf3"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#063d7e"
                        }
                    }
                },
                yAxis: {
                    name:"单位(%)",
                    type: 'value',
                    axisLabel: {
                        textStyle: {
                            color: "#fff"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#fff"
                        }
                    }
                },
                series: [{
                    data: arra,
                    type: 'line',
                    itemStyle: {
                        normal: {
                            lineStyle: {
                                color: '#87d75c'
                            }
                        }
                    },
                }]
            };


            // 使用刚指定的配置项和数据显示图表。
            myCharta.setOption(option);
            option.series[0].data = arrb
            option.xAxis.data= arraunit
            myChartb.setOption(option);
          }
      }
  },
  computed:{

    widthStyle:function(){
      var o = {
        width:"0%"
      }

      if(parseFloat(this.detailData["剩余寿命"]) > 0 ){
        o.width =    parseFloat(this.detailData["剩余寿命"]) /0.06 + '%'  
      }else{
    
      }
      return o;
    },

    rsList(){
      if(this.id == null){
        var arr = []
        for (let index = 0; index < this.data.length; index++) {
          if((this.data[index]['医院'] == this.vala || this.vala == '') &&
            (this.data[index]['生产厂家'] == this.valb || this.valb == '') &&
            (this.data[index]['型号规格'] == this.valc || this.valc == '') &&
            (this.data[index]['风险等级'] == this.vald || this.vald == '') &&
            (this.data[index]['医院所在区县'] == this.vale || this.vale == '') &&
            (this.data[index]['球管安装时间'] == this.valf || this.valf == '') 
          ){
            arr.push(this.data[index])
          }
        }
        return arr
      }else{
        let arr = []
        for (let index = 0; index < this.data.length; index++) {
          if(this.data[index]['ID'] == this.id){
            arr.push(this.data[index])
          }
          
        }
        return arr
       
      }
    },
    tagLista(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院'])
      }
      return new Set(arr)
    },
    tagListb(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['生产厂家'])
      }
      return new Set(arr)
    },
    tagListc(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['型号规格'])
      }
      return new Set(arr)
    },
    tagListd(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['风险等级'])
      }
      return new Set(arr)
    },
    tagListe(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院所在区县'])
      }
      return new Set(arr)
    },
    tagListf(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['球管安装时间'])
      }
      return new Set(arr)
    },
    detailData(){
      if(this.rsList.length == 1){
        return this.rsList[0]
      }
      else{
        return  {
            "ID": null,
            "出厂编号": null,
            "剩余寿命": null,
            "医院": null,
            "医院所在区县": null,
            "医院级别": null,
            "医院纬度": null,
            "医院经度": null,
            "型号规格": null,
            "数据检定日期": null,
            "检定人员": null,
            "球管安装时间": null,
            "生产厂家": null,
            "线性计算结果": null,
            "设备": null,
            "设备纬度": null,
            "设备经度": null,
            "证书编号": null,
            "重复性计算结果": null,
            "风险等级": null
        }
      }
    }

  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
.card_show img{
    display:block;
    width:80%;
    margin:0 auto;
}
</style>



