<template>
  <div class="main"  v-loading="loading">
    <div class="content">
      <Nav index="2" />
      <div class="show_wrap">
        <h1 class="titleh1">
          <b class="lef"></b>
          <b class="rig"></b>
          北京市计量检测科学研究院
        </h1>

        <div class="row height55">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">风险等级占比</h4>
              <div class="card_show">
                <div class="pie" ref="mychartpie"></div>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <h4 class="card_title">筛选条件</h4>
              <div class="card_show">
                <div class="model_table">

                    <div class="col">
                    <div class="row">模糊搜索</div>
                    <div class="row" style="position:relative">
                      <!-- <el-select @change="change($event)" v-model="vala" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in hospitalList"
                          :key="index"
                          :label="item['医院']"
                          :value="item['医院']"
                        ></el-option>
                      </el-select> -->
                    <el-autocomplete
                      class="inline-input mapinput"
                      v-model="searchKey"
                      :fetch-suggestions="querySearch"
                      placeholder="请输入内容"
                      @select="handleSelect"
                    ></el-autocomplete>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">医院名称</div>
                    <div class="row" style="position:relative">
                      <el-select @change="change($event)" v-model="vala" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagLista"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">厂家</div>
                    <div class="row">
                      <el-select v-model="valb" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagListb"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">型号</div>
                    <div class="row">
                      <el-select v-model="valc" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagListc"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">等级</div>
                    <div class="row">
                      <el-select v-model="vald" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagListd"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">所在地</div>
                    <div class="row">
                      <el-select v-model="vale" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagListe"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                  <div class="col">
                    <div class="row">球管安装时间</div>
                    <div class="row">
                      <el-select v-model="valf" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in tagListf"
                          :key="index"
                          :label="item"
                          :value="item"
                        ></el-option>
                      </el-select>
                    </div>
                  </div>
                </div>
                <div class="pie_button">
                  <el-button @click="clear">重 &nbsp; &nbsp; &nbsp; 置</el-button>
                  <el-button  @click="handelsearch">筛 &nbsp; &nbsp; &nbsp; 选</el-button>
                </div>
              </div>
            </div>
          </div>
        </div>
        <div class="row height45">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <h4 class="card_title">筛选结果</h4>
              <div class="card_show">
                <div class="model_table">
                  <div class="col">
                    <div class="row">医院名称</div>
                    <div class="row">厂家</div>
                    <div class="row">型号</div>
                    <div class="row">医院等级</div>
                    <div class="row">所在地</div>
                    <div class="row">球馆安装时间</div>
                    <div class="row">设备ID</div>
                  </div>

                  <div class="col" :key="item.id" v-for="(item,index) in rsList">
                    <div class="row" :class="rsListClass[index]">{{item['医院']}}</div>
                    <div class="row" :class="rsListClass[index]">{{item['生产厂家']}}</div>
                    <div class="row" :class="rsListClass[index]">{{item['型号规格']}}</div>
                    <div class="row" :class="rsListClass[index]">{{item['医院级别']}}</div>
                    <div class="row" :class="rsListClass[index]">{{item['医院所在区县']}}</div>
                    <div class="row" :class="rsListClass[index]">{{item['球管安装时间']}}</div>
                    <div class="row cursor" :class="rsListClass[index]" @click=" toDetail(item['ID'])">{{item['ID']}}</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import echarts from "echarts";

import Nav from "./Nav.vue";

export default {
  name: "Pie",
  components: { Nav },
  data() {
    return {
      loading:true,
      msg: "Welcome to Your Vue.js App",
      chart: null,
      searchKey:"",
      data: [],
      vala: "",
      valb: "",
      valc: "",
      vald: "",
      vale: "",
      valf: "",
      itemData: {
        医院名称: "",
        厂家: "",
        型号: "",
        医院等级: "",
        所在地: "",
        球馆安装时间: "",
        设备ID: ""
      }
    };
  },
  created(){
    console.log(this.gData)
    this.getData()
  },
  methods: {
      handleSelect(val){
        console.log(val)
        let arr = []
        for (let index = 0; index < this.data.length; index++) {
          if(this.data[index]["ID"] == val.id){
            arr.push(this.data[index])
          }
        }
        this.data = arr;
      },
      querySearch(queryString, cb) {
        // var restaurants = this.restaurants;
        // var results = queryString ? restaurants.filter(this.createFilter(queryString)) : restaurants;
        // 调用 callback 返回建议列表的数据

        var rs = [];
        for (let index = 0; index < this.data.length; index++) {
          if( this.data[index]['医院'].indexOf(queryString) !== -1){
            console.log('lll')
            var o = {
              value:this.data[index]['医院'],
              id:this.data[index]['ID'],
              obj:this.data[index]
            }
            rs.push(o)
          }          
        }

        // var results =   [{ "value": "三全鲜食（北新泾店）", "address": "长宁区新渔路144号" },
        //              { "value": "Hot honey 首尔炸鸡（仙霞路）", "address": "上海市长宁区淞虹路661号" }]
        cb(rs);
      },
    change(e) {},
    toDetail(id) {
      this.$router.push({
        name: "Pie",
        query: {
          id: id
        }
      });
    },
    // 筛选结果
    handelsearch(){
      this.initChart()
    },
    clear(){
      this.getData()
      this.searchKey = null,
      this.vala = ""
      this.valb = ""
      this.valc = ""
      this.vald = ""
      this.vale = ""
      this.valf = ""

    },
    getData(){
          this.$axios({
            methods:"get",
            url:"http://47.105.205.80:8880/all",
          }).then((res)=>{
            this.data = res.data;
            this.initChart();
            this.loading = false
          })
    },
    initChart() {

      // 基于准备好的dom，初始化echarts实例
      var data = [];
      let sum = 0;

      var chartData = (() => {
        var arr = [];
        for (let index = 0; index < 4; index++) {
          var lindex = index + 1;
          let o = {
            name: "风险等级" + lindex,
            value: 0
          };
          arr.push(o);
        }
        return arr;
      })();
      for (let index = 0; index < this.rsList.length; index++) {
        if (this.rsList[index]["风险等级"] == 1) {
          chartData[0].value = chartData[0].value + 1;
        }
        if (this.rsList[index]["风险等级"] == 2) {
          chartData[1].value = chartData[1].value + 1;
        }
        if (this.rsList[index]["风险等级"] == 3) {
          chartData[2].value = chartData[2].value + 1;
        }
        if (this.rsList[index]["风险等级"] == 4) {
          chartData[3].value = chartData[3].value + 1;
        }
      }
      console.log(chartData)

      var rschartData = []
      for (let index = 0; index < chartData.length; index++) {
        if(chartData[index].value !== 0){
          rschartData.push(chartData[index])
        }
      }
      console.log(rschartData)

      var colorarr = []
      // ['#D53A35' , '#D48265' ,'#9FDABF' ,'green'],
      for (let index = 0; index < rschartData.length; index++) {
        if(rschartData[index]['name'] == '风险等级1'){
          colorarr.push('#D53A35')
        }
        if(rschartData[index]['name'] == '风险等级2'){
          colorarr.push('#D48265')
          
        }
        if(rschartData[index]['name'] == '风险等级3'){
          colorarr.push('#9FDABF')
          
        }
        if(rschartData[index]['name'] == '风险等级4'){
          colorarr.push('green')
          
        }
        
      }
      console.log(colorarr)
      this.chart = echarts.init(this.$refs.mychartpie);
      var option = {
        tooltip: {
          trigger: "item",
          formatter: "{b} : {c} 个"
        },
        legend: {
          orient: "vertical",
          x: "left",
          data: ["风险等级1", "风险等级2", "风险等级3", "风险等级4"],
          textStyle: {
            color: "#FFF"
          }
        },
        series: [
          {
            name: "风险等级",
            type: "pie",
            radius: "75%",
            center: ["50%", "50%"],
            data: rschartData,
            color:colorarr,
            label: {
              //标签的位置
              normal: {
                show: true,
                position: "inside", //标签的位置
                formatter: "{d}%",
                textStyle: {
                  color: "#fff"
                }
              },
              emphasis: {
                show: true,
                textStyle: {
                  fontWeight: "bold"
                }
              }
            }
          }
        ]
      };
      // 使用刚指定的配置项和数据显示图表。
      this.chart.setOption(option);

      this.data.sort(function() {
        return 0.5 - Math.random();
      });
    }
  },

  computed: {
    // 列表颜色选择
    rsListClass(){
      var arr = [];
        for (let index = 0; index < this.rsList.length; index++) {
          arr.push("level" + this.rsList[index]["风险等级"])
        }
      return arr
    },
    // 筛选结果
    rsList(){
      // vala、valb、valc、vald、vale 、valf 医院名称 厂家 型号 等级 所在地 球管安装时间

      var arr = []
      for (let index = 0; index < this.data.length; index++) {
        if((this.data[index]['医院'] == this.vala || this.vala == '') &&
          (this.data[index]['生产厂家'] == this.valb || this.valb == '') &&
          (this.data[index]['型号规格'] == this.valc || this.valc == '') &&
          (this.data[index]['风险等级'] == this.vald || this.vald == '') &&
          (this.data[index]['医院所在区县'] == this.vale || this.vale == '') &&
          (this.data[index]['球管安装时间'] == this.valf || this.valf == '') 
        ){
          let d =  this.data[index]['球管安装时间'].split('-')
          this.data[index]['球管安装时间'] = d[0] + '-'+d[1]
          arr.push(this.data[index])
        }
      }
      return arr
    },
    tagLista(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院'])
      }
      return new Set(arr)
    },
    tagListb(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['生产厂家'])
      }
      return new Set(arr)
    },
    tagListc(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['型号规格'])
      }
      return new Set(arr)
    },
    tagListd(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['风险等级'])
      }
      return new Set(arr)
    },
    tagListe(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院所在区县'])
      }
      return new Set(arr)
    },
    tagListf(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['球管安装时间'])
      }
      return new Set(arr)
    },

  }
};
</script>

<style scoped>
  h1,
  h2 {
    font-weight: normal;
  }
  ul {
    list-style-type: none;
    padding: 0;
  }
  li {
    display: inline-block;
    margin: 0 10px;
  }
  a {
    color: #42b983;
  }
  .el-select-dropdown {
    left: 1140px !important;
    width: 230px !important;
  }
</style>



