<template>
  <div class="main"  v-loading="loading">
    <div class="content">
    
    <Nav index = '4'/>
      <div class="show_wrap">
            <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京市计量检测科学研究院
            </h1>
        <div class="row height55">
          <div class="col">
            <div class="card active">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">筛选条件</h4>
                      <div class="card_show"> 
                        <div class="model_table">
                          <div class="col">
                            <div class="row">模糊搜索</div>
                            <div class="row" style='position:relative'>
                            <el-autocomplete
                              class="inline-input mapinput"
                              v-model="searchKeyA"
                              :fetch-suggestions="querySearchA"
                              placeholder="请输入内容"
                              @select="handleSelectA"
                            ></el-autocomplete>
                            </div>
                          </div>
                          <div class="col">
                            <div class="row">医院名称</div>
                            <div class="row" style='position:relative'>
                              <el-select @change='change($event)' v-model="vala" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagLista"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">厂家</div>
                            <div class="row">
                              <el-select v-model="valb" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListb"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">型号</div>
                            <div class="row">
                              <el-select v-model="valc" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListc"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">等级</div>
                            <div class="row">
                            <el-select v-model="vald" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListd"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">所在地</div>
                            <div class="row">
                            <el-select v-model="vale" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListe"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">球管安装时间</div>
                            <div class="row">
                            <el-select v-model="valf" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListf"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
          
                        </div>
                          <div class='pie_button'>
                            <el-button @click="reset">重  &nbsp; &nbsp; &nbsp;   置</el-button>
                            <el-button @click="handelsearch">筛  &nbsp; &nbsp; &nbsp;   选</el-button>
                          </div>
                      </div>
                </div>
          </div>
          <div class="col">
            <div class="card active">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">筛选条件</h4>
                      <div class="card_show"> 
                        <div class="model_table">
                          <div class="col">
                            <div class="row">模糊搜索</div>
                            <div class="row" style='position:relative'>
                                <el-input disabled=""></el-input>
                            </div>
                          </div>
                          <div class="col">
                            <div class="row">医院名称</div>
                            <div class="row" style='position:relative'>
                              <el-select :disabled='editArr[0]' :command ='true' @change='change($event)' v-model="vala1" placeholder="请选择">
                                <el-option
                                 
                                  v-for="(item , index) in tagLista1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">厂家</div>
                            <div class="row">
                              <el-select :disabled='editArr[1]' v-model="valb1" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListb1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">型号</div>
                            <div class="row">
                              <el-select :disabled='editArr[2]' v-model="valc1" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListc1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">等级</div>
                            <div class="row">
                            <el-select :disabled='editArr[3]' v-model="vald1" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListd1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">所在地</div>
                            <div class="row">
                            <el-select :disabled='editArr[4]' v-model="vale1" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListe1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
                            <div class="col">
                            <div class="row">球管安装时间</div>
                            <div class="row">
                            <el-select  :disabled='editArr[5]' v-model="valf1" placeholder="请选择">
                                <el-option
                                  v-for="(item , index) in tagListf1"
                                  :key="index"
                                  :label="item"
                                  :value="item">
                                </el-option>
                              </el-select>
                            </div>
                          </div>
          
                        </div>
                          <div class='pie_button'>
                             <el-button @click="resetb">重  &nbsp; &nbsp; &nbsp;   置</el-button>
                            <el-button @click="handelsearch">筛  &nbsp; &nbsp; &nbsp;   选</el-button>
                          </div>
                      </div>
                </div>
        </div>
        </div>
        <div class="row height45">
            <div class="col">
              <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
                <h4 class="card_title">分析结果</h4>
                <div class="card_show" id="cardshow" ref ='mycharta'> 

                </div>
            </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'

import Nav from './Nav.vue'

export default {
  name: 'Pie',
  components:{Nav},
  data () {
    return {
      loading:true,
      searchKeyA:null,
     chart:null,
      data:[],
      vala:'',
      valb:'',
      valc:'',
      vald:'',
      vale:'',
      valf:'',
      vala1:'',
      valb1:'',
      valc1:'',
      vald1:'',
      vale1:'',
      valf1:'',
      itemData:{
            "医院名称": "",
            "厂家": "",
            "型号": "",
            "医院等级": "",
            "所在地": "",
            "球馆安装时间": "",
            "设备ID": ""
      },
    }
  },
  created(){
    this.getData()
  },
  methods: {
      handleSelectA(val){
        console.log(val)
        let arr = []
        for (let index = 0; index < this.data.length; index++) {
          if(this.data[index]["ID"] == val.id){
            arr.push(this.data[index])
          }
        }
        this.data = arr;
      },
      querySearchA(queryString, cb) {
        // var restaurants = this.restaurants;
        // var results = queryString ? restaurants.filter(this.createFilter(queryString)) : restaurants;
        // 调用 callback 返回建议列表的数据

        var rs = [];
        for (let index = 0; index < this.data.length; index++) {
          if( this.data[index]['医院'].indexOf(queryString) !== -1){
            console.log('lll')
            var o = {
              value:this.data[index]['医院'],
              id:this.data[index]['ID'],
              obj:this.data[index]
            }
            rs.push(o)
          }          
        }

        // var results =   [{ "value": "三全鲜食（北新泾店）", "address": "长宁区新渔路144号" },
        //              { "value": "Hot honey 首尔炸鸡（仙霞路）", "address": "上海市长宁区淞虹路661号" }]
        cb(rs);
      },
    reset(){
      this.vala = ''
      this.valb = ''
      this.valc = ''
      this.vald = ''
      this.vale = ''
      this.valf = ''
      this.vala1 = ''
      this.valb1 = ''
      this.valc1 = ''
      this.vald1 = ''
      this.vale1 = ''
      this.valf1 = ''
      this.initChart()
      this.getData()
    },
    resetb(){
      this.vala1 = ''
      this.valb1 = ''
      this.valc1 = ''
      this.vald1 = ''
      this.vale1 = ''
      this.valf1 = ''
      this.initChart()
      this.getData()
    },
    // 筛选方法
    handelsearch(){
      this.initChart()
    },
    change(e ){
      for(var i = 0 ; i < this.data.length ; i++){
        if(this.data[i]['医院名称'] == e){
          localStorage.setItem('index' , i)
        }
      }
    },
    getData(){
          this.$axios({
            methods:"get",
            url:"http://47.105.205.80:8880/all",
          }).then((res)=>{
            this.data = res.data;
            this.initChart()
            this.loading = false
          })
    },

    // 初始化柱状图

    initChart(){




        var arr = []
        for (let index = 0; index < 4; index++) {
            var lindex = index + 1
            let o  = {
              name : "风险等级"+ lindex,
              value : 0
            }
            arr.push(o)
        }


        for (let index = 0; index < this.rsList.length; index++) {
          if(this.rsList[index]['风险等级'] == 1 ){
            arr[0].value  = arr[0].value +1 ; 
          }
          if(this.rsList[index]['风险等级'] == 2 ){
            arr[1].value  = arr[1].value +1 ; 
          }
          if(this.rsList[index]['风险等级'] == 3 ){
            arr[2].value  = arr[2].value +1 ; 
          }
          if(this.rsList[index]['风险等级'] == 4 ){
            arr[3].value  = arr[3].value +1 ; 
          }
        }

        var arrb = []
        for (let index = 0; index < 4; index++) {
            var lindex = index + 1
            let o  = {
              name : "风险等级"+ lindex,
              value : 0
            }
            arrb.push(o)
        }


        for (let index = 0; index < this.rsListB.length; index++) {
          if(this.rsListB[index]['风险等级'] == 1 ){
              arrb[0].value  =  arrb[0].value +1 ; 
          }
          if(this.rsListB[index]['风险等级'] == 2 ){
              arrb[1].value  =  arrb[1].value +1 ; 
          }
          if(this.rsListB[index]['风险等级'] == 3 ){
              arrb[2].value  =  arrb[2].value +1 ; 
          }
          if(this.rsListB[index]['风险等级'] == 4 ){
              arrb[3].value  =  arrb[3].value +1 ; 
          }
        }


        app.title = '坐标轴刻度与标签对齐';

        let option = {
            color: ['red' , '#41E1D4'],
            tooltip : {
                trigger: 'axis',
                axisPointer : {            // 坐标轴指示器，坐标轴触发有效
                    type : 'shadow'        // 默认为直线，可选为：'line' | 'shadow'
                }
            },
            grid: {
                left: '3%',
                right: '4%',
                bottom: '3%',
                containLabel: true
            },
            xAxis : [
                {
                    type : 'category',
                    data : ['风险等级1', '风险等级2', '风险等级3', '风险等级4'],
                    axisTick: {
                        alignWithLabel: true
                    },
                    axisLabel:{
                      color:"#fff"
                    }
                }
            ],
            yAxis : [
                {
                    type : 'value'
                }
            ],
            series : [
                {
                    name:'左边',
                    type:'bar',
                    barWidth: '20%',
                    barGap:0,
                    color:"#41E1D4",
                    data:arr
                },
                {
                    name:'右边',
                    type:'bar',
                    barWidth: '20%',
                    color:"#10A7DB",
                    barGap:0,
                    data:arrb
                }
            ]
        };
        var mycharta  = echarts.init(document.getElementById('cardshow'));
        mycharta.setOption(option);
    }
  },
  mounted() {

        // 基于准备好的dom，初始化echarts实例

        this.initChart()
  },
  computed:{






    //搜索B栏  是不是可以编辑 

    editArr(){
      let arr = [true , true , true , true , true , true , true];

      if(this.vala !== ""){
        arr[0] = false
      }
      if(this.valb !== ""){
        arr[1] = false
      }
      if(this.valc !== ""){
        arr[2] = false
      }
      if(this.vald !== ""){
        arr[3] = false
      }
      if(this.vale !== ""){
        arr[4] = false
      }
      if(this.valf !== ""){
        arr[5] = false
      }
      return arr;
    },


    // 筛选结果
    rsList(){
      // vala、valb、valc、vald、vale 、valf 医院名称 厂家 型号 等级 所在地 球管安装时间

      var arr = []
      for (let index = 0; index < this.data.length; index++) {
        if((this.data[index]['医院'] == this.vala || this.vala == '') &&
          (this.data[index]['生产厂家'] == this.valb || this.valb == '') &&
          (this.data[index]['型号规格'] == this.valc || this.valc == '') &&
          (this.data[index]['风险等级'] == this.vald || this.vald == '') &&
          (this.data[index]['医院所在区县'] == this.vale || this.vale == '') &&
          (this.data[index]['球管安装时间'] == this.valf || this.valf == '') 
        ){
          arr.push(this.data[index])
        }
      }
      return arr
    },
    rsListB(){
      // vala、valb、valc、vald、vale 、valf 医院名称 厂家 型号 等级 所在地 球管安装时间
      var arr = []
      for (let index = 0; index < this.data.length; index++) {
        if((this.data[index]['医院'] == this.vala1 || this.vala1 == '') &&
          (this.data[index]['生产厂家'] == this.valb1 || this.valb1== '') &&
          (this.data[index]['型号规格'] == this.valc1 || this.valc1 == '') &&
          (this.data[index]['风险等级'] == this.vald1 || this.vald1 == '') &&
          (this.data[index]['医院所在区县'] == this.vale1 || this.vale1 == '') &&
          (this.data[index]['球管安装时间'] == this.valf1 || this.valf1 == '') 
        ){
          arr.push(this.data[index])
        }
      }
      return arr
    },
    tagLista(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院'])
      }
      return new Set(arr)
    },
    tagListb(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['生产厂家'])
      }
      return new Set(arr)
    },
    tagListc(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['型号规格'])
      }
      return new Set(arr)
    },
    tagListd(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['风险等级'])
      }
      return new Set(arr)
    },
    tagListe(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['医院所在区县'])
      }
      return new Set(arr)
    },
    tagListf(){
      var arr = []
      for (let index = 0; index < this.rsList.length; index++) {
        arr.push(this.rsList[index]['球管安装时间'])
      }
      return new Set(arr)
    },




    tagLista1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['医院'])
      }
      return new Set(arr)
    },
    tagListb1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['生产厂家'])
      }
      return new Set(arr)
    },
    tagListc1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['型号规格'])
      }
      return new Set(arr)
    },
    tagListd1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['风险等级'])
      }
      return new Set(arr)
    },
    tagListe1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['医院所在区县'])
      }
      return new Set(arr)
    },
    tagListf1(){
      var arr = []
      for (let index = 0; index < this.rsListB.length; index++) {
        arr.push(this.rsListB[index]['球管安装时间'])
      }
      return new Set(arr)
    },


  }
}
</script>

<style scoped>
    h1, h2 {
    font-weight: normal;
    }
    ul {
    list-style-type: none;
    padding: 0;
    }
    li {
    display: inline-block;
    margin: 0 10px;
    }
    a {
    color: #42b983;
    }
    .el-select-dropdown{
        left: 1140px !important;
        width: 230px !important;
    }
</style>



